import Hero from './Hero';
import Protocol from './Protocol';
import Features from './Features';
import Reserves from './Reserves';
import Pricing from './Pricing';
import Updates from './Updates';

export default function Home() {
  return (
    <>
      <Hero />
      <Protocol />
      <Features />
      <Reserves />
      <Pricing />
      <Updates />
    </>
  );
}

import { Routes, Route } from 'react-router-dom';
import Layout from './components/Layout';
import Home from './pages/Home';
import Placeholder from './pages/Placeholder';

export default function App() {
  return (
    <div className="">
      <Routes>
        <Route path="/" element={<Layout />}>
          <Route index element={<Home />} />
          <Route path="learn" element={<Placeholder />} />
          <Route path="trade" element={<Placeholder />} />
          <Route path="markets" element={<Placeholder />} />
          <Route path="leaderboard" element={<Placeholder />} />
          <Route path="*" element={<Placeholder />} />
        </Route>
      </Routes>
    </div>
  );
}

@import url('https://fonts.googleapis.com/css2?family=Space+Mono:wght@400;700&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body {
    background-color: #030303;
    color: #ffffff;
    font-family: ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
    overflow-x: hidden;
    -webkit-font-smoothing: antialiased;
  }
}

@layer utilities {
  .bg-texture {
    background-image: repeating-linear-gradient(
      -45deg,
      rgba(255, 255, 255, 0.015) 0px,
      rgba(255, 255, 255, 0.015) 1px,
      transparent 1px,
      transparent 10px
    );
  }

  .skeuo-card {
    box-shadow: 
      inset 0 1px 0 0 rgba(255, 255, 255, 0.05),
      inset 0 0 20px rgba(0, 0, 0, 0.8),
      0 10px 40px -10px rgba(0, 0, 0, 0.5);
    background: linear-gradient(180deg, rgba(30, 35, 45, 0.8) 0%, rgba(15, 18, 25, 0.9) 100%);
  }

  .skeuo-card-active {
    box-shadow: 
      inset 0 1px 0 0 rgba(255, 255, 255, 0.1),
      inset 0 0 30px rgba(244, 63, 94, 0.05),
      0 0 40px -10px rgba(244, 63, 94, 0.15);
    background: linear-gradient(180deg, rgba(40, 45, 55, 0.9) 0%, rgba(20, 24, 32, 0.95) 100%);
    border: 1px solid rgba(244, 63, 94, 0.2);
  }

  /* Clip Slide Blur Animation */
  .clip-slide {
    --slide-y: 40px;
    --slide-s: 0.95;
    opacity: 0;
    filter: blur(10px);
    transform: translateY(var(--slide-y)) scale(var(--slide-s));
    clip-path: inset(100% 0 0 0);
    transition: opacity 1s cubic-bezier(0.25, 1, 0.5, 1), 
                filter 1s cubic-bezier(0.25, 1, 0.5, 1),
                transform 1s cubic-bezier(0.25, 1, 0.5, 1),
                clip-path 1s cubic-bezier(0.25, 1, 0.5, 1);
  }

  .is-visible.clip-slide,
  .is-visible .clip-slide {
    --slide-y: 0px;
    --slide-s: 1;
    opacity: 1;
    filter: blur(0);
    clip-path: inset(-50% -50% -50% -50%); /* Allow shadows to bleed */
  }

  /* Word Reveal Mask Animation */
  .word-mask {
    display: inline-block;
    overflow: hidden;
    vertical-align: bottom;
    line-height: 1.1;
  }

  .word-inner {
    display: inline-block;
    transform: translateY(110%);
    transition: transform 0.8s cubic-bezier(0.25, 1, 0.5, 1);
    transform-origin: bottom left;
  }

  .is-visible.word-inner,
  .is-visible .word-inner {
    transform: translateY(0);
  }

  /* Stagger Delays */
  .delay-100 { transition-delay: 100ms !important; }
  .delay-200 { transition-delay: 200ms !important; }
  .delay-300 { transition-delay: 300ms !important; }
  .delay-400 { transition-delay: 400ms !important; }
  .delay-500 { transition-delay: 500ms !important; }
  .delay-600 { transition-delay: 600ms !important; }
  .delay-700 { transition-delay: 700ms !important; }
  .delay-800 { transition-delay: 800ms !important; }

  /* Holodex 3D Layout */
  .holodex-container {
    perspective: 1200px;
    transform-style: preserve-3d;
  }

  .holodex-item {
    transition: all 0.6s cubic-bezier(0.25, 1, 0.5, 1);
    transform-style: preserve-3d;
    backface-visibility: hidden;
    will-change: transform, opacity;
  }

  @media (min-width: 768px) {
    /* Base State: Center pops out, edges push back */
    .holodex-container:not(:hover) .holodex-left .holodex-item { 
      transform: translateZ(-80px) rotateY(12deg) translateX(30px) scale(0.9);
      opacity: 0.5;
    }
    .holodex-container:not(:hover) .holodex-center .holodex-item { 
      transform: translateZ(40px) scale(1.05);
      z-index: 10;
      box-shadow: 0 30px 60px -10px rgba(0,0,0,0.8);
      opacity: 1;
    }
    .holodex-container:not(:hover) .holodex-right .holodex-item { 
      transform: translateZ(-80px) rotateY(-12deg) translateX(-30px) scale(0.9);
      opacity: 0.5;
    }

    /* Container Hovered: push everything back slightly */
    .holodex-container:hover .holodex-item {
      transform: translateZ(-40px) scale(0.95);
      opacity: 0.6;
      z-index: 1;
    }

    /* Specific Item Hovered: pop it out aggressively */
    .holodex-container .holodex-item:hover {
      transform: translateZ(60px) scale(1.05);
      opacity: 1;
      z-index: 20;
      box-shadow: 0 40px 80px -10px rgba(0,0,0,0.9);
      border-color: rgba(244, 63, 94, 0.4);
    }
  }

  /* Legacy Reveal Fallback */
  .reveal-up {
    opacity: 0;
    transform: translateY(40px);
    transition: opacity 1.2s cubic-bezier(0.16, 1, 0.3, 1), transform 1.2s cubic-bezier(0.16, 1, 0.3, 1);
  }

  .reveal-up.is-visible {
    opacity: 1;
    transform: translateY(0);
  }
}

import { useEffect, useRef } from 'react';

export default function NexusEngine() {
  const canvasRef = useRef(null);
  const gridRef = useRef(null);

  // WebGL Renderer Effect
  useEffect(() => {
    const canvas = canvasRef.current;
    const gl = canvas.getContext('webgl2');

    if (!gl) {
      console.error('WebGL2 not supported');
      return;
    }

    let animationFrameId;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      gl.viewport(0, 0, canvas.width, canvas.height);
    };

    window.addEventListener('resize', resize);
    resize();

    const vsSource = `#version 300 es
      in float a_t;
      in float a_instance;

      uniform float u_time;
      uniform vec2 u_resolution;
      uniform float u_instances;

      out float v_instance;

      void main() {
          v_instance = a_instance;

          // Normalized parameters
          float time = u_time * 0.0004;
          float id = (a_instance / u_instances) * 2.0 - 1.0; // -1 to 1 across ribbon
          float u = a_t * 3.14159 * 2.0; // One complete loop for the heart

          // --- Parametric 3D Heart ---
          vec3 p;

          // Base heart shape formulas
          float s = sin(u);
          p.x = 2.0 * (s * s * s);
          p.y = 1.6 * cos(u) - 0.6 * cos(2.0 * u) - 0.2 * cos(3.0 * u) - 0.1 * cos(4.0 * u);

          // Center vertically and add 3D depth wave
          p.y += 0.2; 
          p.z = sin(u * 2.0 + time * 1.5) * 0.6;

          // Gentle pulse effect
          float pulse = 1.0 + 0.05 * sin(time * 5.0);
          p *= pulse;

          // Deform to create ribbon thickness (parallel lines)
          float spread = 0.5;
          p.x += sin(u * 4.0 + time) * id * spread * 0.4;
          p.y += cos(u * 4.0 + time) * id * spread * 0.4;
          p.z += sin(u * 2.0) * id * spread;

          // Slow global rotation
          float rx = sin(time * 0.5) * 0.2; // Limited X tilt to keep shape recognizable
          float ry = time * 0.4;            // Continuous Y spin

          mat2 rotX = mat2(cos(rx), -sin(rx), sin(rx), cos(rx));
          mat2 rotY = mat2(cos(ry), -sin(ry), sin(ry), cos(ry));

          vec2 yz = rotX * vec2(p.y, p.z);
          p.y = yz.x; p.z = yz.y;

          vec2 xz = rotY * vec2(p.x, p.z);
          p.x = xz.x; p.z = xz.y;

          // Simple perspective projection
          float z_dist = 6.0;
          float z_factor = z_dist / (z_dist - p.z);
          vec2 pos2d = p.xy * z_factor;

          // Aspect ratio correction & scaling
          float aspect = u_resolution.x / u_resolution.y;
          pos2d.x /= aspect;

          // Scale to fit viewport nicely
          pos2d *= 0.45; 

          // Subtle breathing scale
          pos2d *= 1.0 + sin(time * 2.0) * 0.02;

          gl_Position = vec4(pos2d, 0.0, 1.0);
      }
    `;

    const fsSource = `#version 300 es
      precision highp float;

      in float v_instance;
      uniform float u_instances;

      out vec4 outColor;

      void main() {
          // Vibrant red tone for the remix
          vec3 coreColor = vec3(1.0, 0.1, 0.15); 

          // Fade color slightly towards the darker red edges of the ribbon bundle
          float edgeFactor = abs((v_instance / u_instances) * 2.0 - 1.0);
          vec3 finalColor = mix(coreColor, vec3(0.5, 0.0, 0.05), pow(edgeFactor, 2.0));

          // Additive blending alpha
          outColor = vec4(finalColor, 0.4);
      }
    `;

    const createShader = (type, source) => {
      const shader = gl.createShader(type);
      gl.shaderSource(shader, source);
      gl.compileShader(shader);
      if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {
        console.error(gl.getShaderInfoLog(shader));
        gl.deleteShader(shader);
        return null;
      }
      return shader;
    };

    const vertexShader = createShader(gl.VERTEX_SHADER, vsSource);
    const fragmentShader = createShader(gl.FRAGMENT_SHADER, fsSource);
    const program = gl.createProgram();

    gl.attachShader(program, vertexShader);
    gl.attachShader(program, fragmentShader);
    gl.linkProgram(program);
    gl.useProgram(program);

    const segments = 800;    
    const instances = 60;    

    const tData = new Float32Array(segments);
    for (let i = 0; i < segments; i++) tData[i] = i / (segments - 1);

    const instanceData = new Float32Array(instances);
    for (let i = 0; i < instances; i++) instanceData[i] = i;

    const tBuffer = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, tBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, tData, gl.STATIC_DRAW);
    const a_t = gl.getAttribLocation(program, "a_t");
    gl.enableVertexAttribArray(a_t);
    gl.vertexAttribPointer(a_t, 1, gl.FLOAT, false, 0, 0);

    const instanceBuffer = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, instanceBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, instanceData, gl.STATIC_DRAW);
    const a_instance = gl.getAttribLocation(program, "a_instance");
    gl.enableVertexAttribArray(a_instance);
    gl.vertexAttribPointer(a_instance, 1, gl.FLOAT, false, 0, 0);
    gl.vertexAttribDivisor(a_instance, 1); 

    const u_time = gl.getUniformLocation(program, "u_time");
    const u_resolution = gl.getUniformLocation(program, "u_resolution");
    const u_instances = gl.getUniformLocation(program, "u_instances");

    gl.uniform1f(u_instances, instances);

    gl.enable(gl.BLEND);
    gl.blendFunc(gl.SRC_ALPHA, gl.ONE); 
    gl.disable(gl.DEPTH_TEST);

    const render = (time) => {
      gl.clearColor(0.0, 0.0, 0.0, 1.0);
      gl.clear(gl.COLOR_BUFFER_BIT);

      gl.uniform1f(u_time, time);
      gl.uniform2f(u_resolution, canvas.width, canvas.height);

      gl.drawArraysInstanced(gl.LINE_STRIP, 0, segments, instances);

      animationFrameId = requestAnimationFrame(render);
    };

    animationFrameId = requestAnimationFrame(render);

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);

      gl.deleteProgram(program);
      gl.deleteShader(vertexShader);
      gl.deleteShader(fragmentShader);
      gl.deleteBuffer(tBuffer);
      gl.deleteBuffer(instanceBuffer);
    };
  }, []);

  // Parallax Effect
  useEffect(() => {
    const handleMouseMove = (e) => {
      if (!gridRef.current) return;
      const x = (e.clientX / window.innerWidth - 0.5) * 20;
      const y = (e.clientY / window.innerHeight - 0.5) * 20;
      gridRef.current.style.backgroundPosition = `calc(50% + ${x}px) calc(50% + ${y}px)`;
    };

    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  return (
    <div className="fixed inset-0 z-0 pointer-events-none select-none overflow-hidden bg-[#030303] text-white" style={{ fontFamily: "'Space Mono', monospace" }}>
      {/* 3D WebGL Canvas */}
      <canvas ref={canvasRef} className="absolute inset-0 z-0 w-full h-full pointer-events-none"></canvas>

      {/* Grid Pattern with Parallax */}
      <div 
        ref={gridRef} 
        className="absolute inset-0 z-10 pointer-events-none transition-all duration-100 ease-out will-change-[background-position]"
        style={{ 
          backgroundSize: '80px 80px', 
          backgroundImage: 'linear-gradient(to right, rgba(255, 255, 255, 0.07) 1px, transparent 1px), linear-gradient(to bottom, rgba(255, 255, 255, 0.07) 1px, transparent 1px)', 
          backgroundPosition: 'center center' 
        }}
      ></div>

      {/* Diagonal Texture Overlay */}
      <div 
        className="absolute inset-0 z-10 pointer-events-none mix-blend-overlay"
        style={{ 
          backgroundImage: 'repeating-linear-gradient(-45deg, transparent, transparent 4px, rgba(255, 255, 255, 0.02) 4px, rgba(255, 255, 255, 0.02) 5px)' 
        }}
      ></div>

      {/* HUD Elements Overlay */}
      <main className="absolute inset-0 z-20 pointer-events-none flex flex-col justify-between p-6 md:p-[80px]">

        {/* Top Row */}
        <div className="flex justify-between items-start w-full relative">
          <div className="text-[0.65rem] leading-[1.2] tracking-[0.2em] uppercase nexus-gs-reveal" style={{ animationDelay: '0.2s' }}>
            <span className="text-gray-400">SYSTEM ///</span> INITIALIZE<br />
            <span className="text-gray-400">///</span> V.09
          </div>

          <div 
            className="w-8 h-8 opacity-80 nexus-gs-reveal mt-2 mr-2" 
            style={{ 
              animationDelay: '0.3s',
              background: 'repeating-linear-gradient(45deg, transparent, transparent 2px, rgba(255, 255, 255, 0.6) 2px, rgba(255, 255, 255, 0.6) 4px)' 
            }}
          ></div>

          <div className="absolute top-1/2 left-[30%] w-[20vw] h-[1px] bg-white/10 -translate-y-1/2 nexus-gs-reveal" style={{ animationDelay: '0.4s' }}></div>
        </div>

        {/* Center Interactive Area */}
        <div className="absolute top-1/2 left-[10%] md:left-[20%] -translate-y-1/2 nexus-gs-reveal pointer-events-auto" style={{ animationDelay: '0.5s' }}>
          <div className="absolute -right-12 top-1/2 w-8 h-[1px] bg-white/30 -translate-y-1/2"></div>
        </div>

        {/* Middle Crosshairs / Guides (Hidden on mobile for clarity) */}
        <div className="absolute top-[40%] left-[50%] w-3 h-3 border-t border-l border-white/40 -translate-x-1/2 -translate-y-1/2 hidden md:block"></div>
        <div className="absolute bottom-[30%] right-[30%] w-3 h-3 border-b border-r border-white/40 hidden md:block"></div>
        <div className="absolute top-[20%] right-[40%] w-[1px] h-4 bg-white/30 hidden md:block"></div>

        {/* Bottom Row */}
        <div className="flex justify-between items-end w-full relative">

          <div className="text-[0.65rem] leading-[1.2] tracking-[0.2em] uppercase text-right nexus-gs-reveal mb-2 mr-2 ml-auto" style={{ animationDelay: '0.6s' }}>
            <span className="text-gray-400">///</span><br />
            ENGAGE
          </div>

          <div className="absolute top-[-10vh] left-0 right-[-10vw] bottom-0 pointer-events-none opacity-30">
            <div className="absolute w-[12px] h-[12px] border-white/40 top-0 left-0 border-t border-l"></div>
            <div className="absolute w-[12px] h-[12px] border-white/40 bottom-0 left-0 border-b border-l"></div>
          </div>
        </div>
      </main>
    </div>
  );
}

import { useMemo } from 'react';

export default function MaskedText({ text, className = "", delayStart = 0, stagger = 100 }) {
  // Split by newline to preserve explicit line breaks
  const lines = useMemo(() => text.split('\n'), [text]);

  let wordIndex = 0;

  return (
    <span className={`block ${className}`}>
      {lines.map((line, lineIdx) => (
        <span key={lineIdx} className="block">
          {line.split(' ').map((word, i) => {
            if (!word) return null;
            const currentIdx = wordIndex++;
            return (
              <span key={`${lineIdx}-${i}`} className="word-mask mr-[0.3em] inline-block">
                <span 
                  className="word-inner inline-block"
                  style={{ transitionDelay: `${delayStart + currentIdx * stagger}ms` }}
                >
                  {word}
                </span>
              </span>
            );
          })}
        </span>
      ))}
    </span>
  );
}

import { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import clsx from 'clsx';

export default function Navbar() {
  const location = useLocation();
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };

    window.addEventListener('scroll', handleScroll);
    // Initialize state on mount
    handleScroll();

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Learn', path: '/learn' },
    { name: 'Trade', path: '/trade' },
    { name: 'Markets', path: '/markets' },
    { name: 'Leaderboard', path: '/leaderboard' },
  ];

  return (
    <nav className={clsx(
      "sticky top-0 w-full max-w-7xl px-6 flex items-center justify-between z-50 transition-all duration-300",
      scrolled 
        ? "py-4 bg-[#030303]/80 backdrop-blur-md border-b border-white/[0.1] shadow-lg" 
        : "py-6 bg-transparent border-b border-white/[0.05]"
    )}>
      {/* Corner Brackets */}
      <div className={clsx(
        "absolute top-0 left-0 w-2 h-2 border-l border-t transition-colors duration-300",
        scrolled ? "border-white/40" : "border-white/20"
      )}></div>
      <div className={clsx(
        "absolute top-0 right-0 w-2 h-2 border-r border-t transition-colors duration-300",
        scrolled ? "border-white/40" : "border-white/20"
      )}></div>

      <Link to="/" className="flex items-center space-x-3 group cursor-pointer">
        <div className="w-8 h-8 flex items-center justify-center border border-white/10 rounded-sm group-hover:border-white/30 transition-colors">
          <iconify-icon icon="solar:round-double-alt-arrow-down-outline" class="text-xl text-white" width="20" height="20" style={{ color: 'rgb(255, 255, 255)' }}></iconify-icon>
        </div>
        <div className="flex flex-col">
          <span className="text-sm font-medium tracking-wide uppercase leading-none group-hover:text-rose-500 transition-colors">NovaChain</span>
          <span className="text-[0.65rem] text-white/40 tracking-widest uppercase mt-0.5">Trading Protocol</span>
        </div>
      </Link>

      <div className="hidden md:flex space-x-8 text-xs font-medium tracking-widest uppercase text-white/60">
        {navLinks.map((link) => (
          <Link 
            key={link.name} 
            to={link.path} 
            className={clsx(
              "transition-colors hover:text-white",
              location.pathname === link.path ? "text-rose-500" : ""
            )}
          >
            {link.name}
          </Link>
        ))}
      </div>

      <div className="hidden md:flex w-24 justify-end">
         <button className="px-4 py-1.5 border border-rose-500/50 text-rose-500 text-[0.65rem] tracking-widest uppercase rounded-sm hover:bg-rose-500 hover:text-white transition-all">
            Connect
         </button>
      </div> 
    </nav>
  );
}

import clsx from 'clsx';

export default function Toggle({ checked, onChange, label }) {
  return (
    <label className="flex items-center cursor-pointer group">
      <div className="relative">
        <input 
          type="checkbox" 
          className="sr-only" 
          checked={checked} 
          onChange={(e) => onChange(e.target.checked)} 
        />
        <div className={clsx(
          "w-8 h-4 rounded-full relative transition-colors duration-200",
          checked ? "bg-[#f7931a]" : "bg-white/20 group-hover:bg-white/30"
        )}>
          <div className={clsx(
            "w-4 h-4 bg-white rounded-full absolute left-0 top-0 transition-transform duration-300 ease-spring",
            checked ? "transform translate-x-[100%] border-[#f7931a]" : "border-gray-300"
          )}></div>
        </div>
      </div>
      {label && <span className="ml-3 text-xs font-medium text-white/80 select-none">{label}</span>}
    </label>
  );
}

import { useState } from 'react';
import { Outlet } from 'react-router-dom';
import Navbar from './Navbar';
import Footer from './Footer';
import NexusEngine from './NexusEngine';

export default function Layout() {
  const [openFaq, setOpenFaq] = useState(0);

  const faqs = [
    {
      question: "What is NovaChain Protocol?",
      answer: "NovaChain is a high-performance Layer 2 derivatives DEX offering ultra-low latency trading with unified cross-margin capabilities, built specifically for professional and institutional traders."
    },
    {
      question: "How do I start trading?",
      answer: "Simply connect your Web3 wallet, deposit supported collateral (USDC or USDT), and you can instantly start trading perpetual contracts with up to 100x leverage. No KYC is required for standard accounts."
    },
    {
      question: "Are my funds secure?",
      answer: "Yes. Our smart contracts are fully audited by leading security firms. All user funds are held in non-custodial smart contracts or via institutional-grade MPC custody partners with real-time proof of reserves."
    },
    {
      question: "What are the trading fees?",
      answer: "We offer highly competitive fees starting at 0.02% for makers and 0.05% for takers. Staking $NOVA tokens can reduce these fees by up to 50% and unlock additional platform benefits."
    }
  ];

  return (
    <div className="relative antialiased selection:bg-rose-500 selection:text-white min-h-screen">
      {/* Background WebGL Engine & HUD */}
      <NexusEngine />

      {/* Global Grid Lines Container */}
      <div className="fixed inset-0 w-full h-full z-0 pointer-events-none flex justify-center">
        <div className="w-full max-w-7xl h-full border-x border-white/[0.03] relative">
          <div className="absolute left-1/3 top-0 bottom-0 w-px bg-white/[0.02]"></div>
          <div className="absolute right-1/3 top-0 bottom-0 w-px bg-white/[0.02]"></div>
        </div>
      </div>

      {/* Main Content Wrapper */}
      <div className="relative z-10 w-full flex flex-col items-center">
        <Navbar />
        <main className="w-full flex flex-col items-center">
          <Outlet />
        </main>

        {/* Global FAQ Section */}
        <div className="w-full max-w-3xl px-6 py-24 flex flex-col relative z-10 mt-10">
          <div className="mb-12 w-full text-center flex flex-col items-center">
            <div className="flex items-center space-x-4 mb-4 text-[0.65rem] tracking-widest uppercase text-rose-500 font-medium">
              <span>Support</span>
